{
  "name": "MathDash: Neon Cards",
  "description": "A high-energy, Geometry Dash-inspired math card game for 8-year-olds. Master addition, subtraction, and multiplication with neon visuals, combos, and level-based progression.",
  "requestFramePermissions": ["microphone"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  START = 'START',
  PLAYING = 'PLAYING',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  GAMEOVER = 'GAMEOVER',
  LEADERBOARD = 'LEADERBOARD'
}

export interface MathProblem {
  id: string;
  question: string;
  answer: number;
  options: number[];
  difficulty: number;
}

export interface PlayerStats {
  score: number;
  level: number;
  experience: number;
  highScore: number;
  combos: number;
}

export interface LeaderboardEntry {
  name: string;
  score: number;
  level: number;
  date: string;
}

export interface LevelConfig {
  title: string;
  description: string;
  targetExp: number;
  operations: ('+' | '-' | '*')[];
  maxNumber: number;
  timeLimit: number;
}

import { LevelConfig } from './types';

export const LEVELS: LevelConfig[] = [
  {
    title: "Level 1: Genesis",
    description: "Addition within 10. Simple and clean.",
    targetExp: 100,
    operations: ['+'],
    maxNumber: 10,
    timeLimit: 10,
  },
  {
    title: "Level 2: Pulse",
    description: "Subtraction steps in. Stay sharp.",
    targetExp: 250,
    operations: ['+', '-'],
    maxNumber: 15,
    timeLimit: 12,
  },
  {
    title: "Level 3: Velocity",
    description: "Faster responses needed. Numbers up to 20.",
    targetExp: 500,
    operations: ['+', '-'],
    maxNumber: 20,
    timeLimit: 10,
  },
  {
    title: "Level 4: Electron",
    description: "Addition of double digits.",
    targetExp: 800,
    operations: ['+', '-'],
    maxNumber: 50,
    timeLimit: 15,
  },
  {
    title: "Level 5: Multiplication X",
    description: "Introduction to simple multiplication (2, 5, 10).",
    targetExp: 1200,
    operations: ['*', '+'],
    maxNumber: 10, // For multiplication, this acts differently
    timeLimit: 20,
  },
  {
    title: "Level 6: Overdrive",
    description: "Mixed operations at high speed.",
    targetExp: 2000,
    operations: ['+', '-', '*'],
    maxNumber: 100,
    timeLimit: 12,
  }
];

export const INITIAL_STATS = {
  score: 0,
  level: 1,
  experience: 0,
  highScore: 0,
  combos: 0
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getEncouragement = async (combo: number, level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The player is 8 years old. They just hit a combo of ${combo} in Level ${level}. Give a very short, high-energy 2-3 word phrase in the style of "Geometry Dash" or a cool game announcer. Examples: "UNSTOPPABLE!", "PURE SKILL!", "NEON MASTER!".`,
      config: {
        maxOutputTokens: 20,
      }
    });
    return response.text.trim().toUpperCase() || "AMAZING!";
  } catch (error) {
    return "GREAT JOB!";
  }
};

export const getMathFact = async (level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Give a fun, short math fact for an 8-year-old child that relates to level ${level} concepts (Addition/Subtraction/Logic). Keep it simple and encouraging. Maximum 15 words.`,
      config: {
        maxOutputTokens: 50,
      }
    });
    return response.text.trim();
  } catch (error) {
    return "Math is the language of the universe!";
  }
};

import React from 'react';

interface NeonButtonProps {
  children: React.ReactNode;
  onClick: () => void;
  className?: string;
  variant?: 'cyan' | 'pink' | 'purple';
  disabled?: boolean;
}

const NeonButton: React.FC<NeonButtonProps> = ({ 
  children, 
  onClick, 
  className = '', 
  variant = 'cyan',
  disabled = false
}) => {
  const variantStyles = {
    cyan: 'border-cyan-400 text-cyan-400 hover:bg-cyan-400/20 shadow-[0_0_15px_rgba(34,211,238,0.4)]',
    pink: 'border-pink-400 text-pink-400 hover:bg-pink-400/20 shadow-[0_0_15px_rgba(244,114,182,0.4)]',
    purple: 'border-purple-500 text-purple-500 hover:bg-purple-500/20 shadow-[0_0_15px_rgba(168,85,247,0.4)]',
  };

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`
        px-8 py-3 
        border-2 
        font-orbitron font-bold uppercase tracking-widest
        transition-all duration-300 transform hover:scale-105 active:scale-95
        rounded-lg
        ${variantStyles[variant]}
        ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
        ${className}
      `}
    >
      {children}
    </button>
  );
};

export default NeonButton;

import React, { useState, useEffect } from 'react';
import { MathProblem } from '../types';

interface GameCardProps {
  problem: MathProblem;
  onAnswer: (selected: number) => void;
  isLocked: boolean;
}

const GameCard: React.FC<GameCardProps> = ({ problem, onAnswer, isLocked }) => {
  const [selected, setSelected] = useState<number | null>(null);

  useEffect(() => {
    setSelected(null);
  }, [problem]);

  const handleSelect = (val: number) => {
    if (isLocked) return;
    setSelected(val);
    onAnswer(val);
  };

  return (
    <div className="w-full max-w-md perspective-1000 animate-in fade-in zoom-in duration-500">
      <div className="bg-slate-900/80 border-4 border-cyan-400 rounded-2xl p-8 shadow-[0_0_30px_rgba(34,211,238,0.3)] backdrop-blur-md">
        <div className="text-center mb-10">
          <span className="text-sm font-orbitron text-cyan-400 uppercase tracking-tighter opacity-70 mb-2 block">Analyze Problem</span>
          <h2 className="text-6xl font-orbitron font-black neon-text-cyan">
            {problem.question}
          </h2>
        </div>

        <div className="grid grid-cols-2 gap-4">
          {problem.options.map((opt, i) => (
            <button
              key={`${problem.id}-${i}`}
              onClick={() => handleSelect(opt)}
              disabled={isLocked}
              className={`
                p-6 rounded-xl border-2 font-orbitron text-2xl font-bold transition-all duration-200
                ${selected === opt 
                  ? (opt === problem.answer ? 'bg-green-500/40 border-green-400 shadow-[0_0_20px_rgba(74,222,128,0.5)]' : 'bg-red-500/40 border-red-400 shadow-[0_0_20px_rgba(248,113,113,0.5)]')
                  : 'bg-slate-800 border-slate-700 hover:border-cyan-400 hover:scale-105 hover:bg-slate-700'
                }
                ${isLocked ? 'cursor-default' : 'cursor-pointer'}
              `}
            >
              {opt}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default GameCard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, MathProblem, PlayerStats, LeaderboardEntry } from './types';
import { LEVELS, INITIAL_STATS } from './constants';
import { getEncouragement, getMathFact } from './services/geminiService';
import NeonButton from './components/NeonButton';
import GameCard from './components/GameCard';
import { Trophy, Zap, Clock, Star, BrainCircuit, RotateCcw, Play, BarChart2 } from 'lucide-react';

const App: React.FC = () => {
  // Game State
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS);
  const [currentProblem, setCurrentProblem] = useState<MathProblem | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [combo, setCombo] = useState<number>(0);
  const [feedback, setFeedback] = useState<string>('');
  const [mathFact, setMathFact] = useState<string>('');
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [isAnswering, setIsAnswering] = useState<boolean>(false);
  const [shaking, setShaking] = useState<boolean>(false);

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  // Load Leaderboard
  useEffect(() => {
    const saved = localStorage.getItem('mathdash_leaderboard');
    if (saved) setLeaderboard(JSON.parse(saved));
  }, []);

  // Generate Problem based on level
  const generateProblem = useCallback(() => {
    const config = LEVELS[stats.level - 1];
    const op = config.operations[Math.floor(Math.random() * config.operations.length)];
    let n1, n2, answer;

    if (op === '*') {
      n1 = Math.floor(Math.random() * 5) + 1; // 1-5
      n2 = Math.floor(Math.random() * 10) + 1; // 1-10
      answer = n1 * n2;
    } else if (op === '-') {
      n1 = Math.floor(Math.random() * config.maxNumber) + 5;
      n2 = Math.floor(Math.random() * n1);
      answer = n1 - n2;
    } else {
      n1 = Math.floor(Math.random() * config.maxNumber);
      n2 = Math.floor(Math.random() * config.maxNumber);
      answer = n1 + n2;
    }

    const options = new Set<number>();
    options.add(answer);
    while (options.size < 4) {
      const offset = Math.floor(Math.random() * 10) - 5;
      const fake = Math.max(0, answer + (offset === 0 ? 3 : offset));
      options.add(fake);
    }

    const problem: MathProblem = {
      id: Math.random().toString(36).substr(2, 9),
      question: `${n1} ${op === '*' ? '×' : op} ${n2}`,
      answer,
      options: Array.from(options).sort(() => Math.random() - 0.5),
      difficulty: stats.level
    };

    setCurrentProblem(problem);
    setTimeLeft(config.timeLimit);
    setIsAnswering(false);
  }, [stats.level]);

  // Start Game
  const startGame = () => {
    setStats(INITIAL_STATS);
    setGameState(GameState.PLAYING);
    setCombo(0);
    generateProblem();
  };

  // Timer logic
  useEffect(() => {
    if (gameState === GameState.PLAYING && timeLeft > 0 && !isAnswering) {
      timerRef.current = setTimeout(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && gameState === GameState.PLAYING && !isAnswering) {
      handleAnswer(-1); // Fail due to time
    }
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [timeLeft, gameState, isAnswering]);

  // Handle Answer
  const handleAnswer = async (selected: number) => {
    if (!currentProblem || isAnswering) return;

    setIsAnswering(true);
    const isCorrect = selected === currentProblem.answer;

    if (isCorrect) {
      const newCombo = combo + 1;
      setCombo(newCombo);
      const points = 10 * stats.level * (newCombo > 5 ? 2 : 1);

      setStats(prev => {
        const newExp = prev.experience + 10;
        const config = LEVELS[prev.level - 1];

        // Level Up Check
        if (newExp >= config.targetExp && prev.level < LEVELS.length) {
          return {
            ...prev,
            score: prev.score + points,
            experience: 0,
            level: prev.level + 1
          };
        }

        return {
          ...prev,
          score: prev.score + points,
          experience: newExp
        };
      });

      // AI Commentary for streaks
      if (newCombo % 5 === 0) {
        const msg = await getEncouragement(newCombo, stats.level);
        setFeedback(msg);
        setTimeout(() => setFeedback(''), 2000);
      }

      // Progress to next problem
      setTimeout(() => {
        generateProblem();
      }, 400);

    } else {
      setShaking(true);
      setCombo(0);
      setStats(prev => ({
        ...prev,
        highScore: Math.max(prev.highScore, prev.score)
      }));

      setTimeout(() => setShaking(false), 500);

      // End game on mistake (Geometry Dash style: one crash and you're done)
      setGameState(GameState.GAMEOVER);

      // Update leaderboard
      const newEntry: LeaderboardEntry = {
        name: "PLAYER_" + Math.floor(Math.random() * 999),
        score: stats.score,
        level: stats.level,
        date: new Date().toLocaleDateString()
      };
      const updatedLeaderboard = [...leaderboard, newEntry]
        .sort((a, b) => b.score - a.score)
        .slice(0, 10);
      setLeaderboard(updatedLeaderboard);
      localStorage.setItem('mathdash_leaderboard', JSON.stringify(updatedLeaderboard));

      // Load a fun math fact for the death screen
      const fact = await getMathFact(stats.level);
      setMathFact(fact);
    }
  };

  // UI Components
  const ProgressBar = () => {
    const config = LEVELS[stats.level - 1];
    const percentage = (stats.experience / config.targetExp) * 100;
    return (
      <div className="w-full bg-slate-800 h-4 rounded-full border border-slate-700 overflow-hidden mb-8">
        <div 
          className="h-full bg-cyan-400 shadow-[0_0_15px_rgba(34,211,238,0.8)] transition-all duration-500" 
          style={{ width: `${percentage}%` }}
        />
      </div>
    );
  };

  return (
    <div className={`min-h-screen bg-[#0f172a] bg-grid text-white flex flex-col items-center justify-center p-6 ${shaking ? 'animate-bounce' : ''}`}>

      {/* HUD - Always visible during play */}
      {gameState === GameState.PLAYING && (
        <div className="fixed top-0 left-0 w-full p-6 flex justify-between items-start z-10">
          <div className="flex flex-col gap-2">
            <div className="flex items-center gap-2 bg-slate-900/80 border border-cyan-400 p-3 rounded-lg backdrop-blur-md">
              <Zap className="text-cyan-400 w-5 h-5 fill-cyan-400" />
              <span className="font-orbitron font-bold text-xl">{stats.score}</span>
            </div>
            <div className="text-sm font-orbitron text-pink-400 uppercase tracking-widest px-1">
              COMBO x{combo}
            </div>
          </div>

          <div className="flex flex-col items-center gap-2">
            <h1 className="font-orbitron font-black text-2xl tracking-tighter neon-text-cyan">
              {LEVELS[stats.level - 1].title}
            </h1>
            <div className="w-64">
              <ProgressBar />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className={`flex items-center gap-2 bg-slate-900/80 border p-3 rounded-lg backdrop-blur-md ${timeLeft < 5 ? 'border-red-500 animate-pulse' : 'border-cyan-400'}`}>
              <Clock className={`w-5 h-5 ${timeLeft < 5 ? 'text-red-500' : 'text-cyan-400'}`} />
              <span className="font-orbitron font-bold text-xl">{timeLeft}s</span>
            </div>
          </div>
        </div>
      )}

      {/* Start Screen */}
      {gameState === GameState.START && (
        <div className="text-center max-w-2xl animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="mb-8 relative inline-block">
             <div className="w-24 h-24 border-4 border-cyan-400 bg-cyan-400/10 rotate-45 mx-auto mb-6 flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.4)]">
                <BrainCircuit className="w-12 h-12 text-cyan-400 -rotate-45" />
             </div>
             <h1 className="text-7xl font-orbitron font-black mb-4 tracking-tighter neon-text-cyan italic">
               MATH<span className="text-pink-500">DASH</span>
             </h1>
             <p className="text-slate-400 font-orbitron tracking-widest uppercase">Neon Logic Engine 3.0</p>
          </div>

          <div className="flex flex-col gap-4 items-center">
            <NeonButton onClick={startGame} className="w-full sm:w-64 text-xl">
              <div className="flex items-center justify-center gap-2">
                <Play className="fill-current" />
                INITIATE
              </div>
            </NeonButton>
            <NeonButton 
              variant="purple" 
              onClick={() => setGameState(GameState.LEADERBOARD)} 
              className="w-full sm:w-64"
            >
              <div className="flex items-center justify-center gap-2">
                <Trophy size={18} />
                ARCHIVES
              </div>
            </NeonButton>
          </div>
        </div>
      )}

      {/* Game Play */}
      {gameState === GameState.PLAYING && currentProblem && (
        <div className="relative">
          {feedback && (
            <div className="absolute -top-20 left-1/2 -translate-x-1/2 w-full text-center pointer-events-none animate-bounce">
              <h2 className="text-4xl font-orbitron font-black text-pink-500 italic neon-text-pink drop-shadow-lg">
                {feedback}
              </h2>
            </div>
          )}
          <GameCard 
            problem={currentProblem} 
            onAnswer={handleAnswer} 
            isLocked={isAnswering} 
          />
        </div>
      )}

      {/* Game Over Screen */}
      {gameState === GameState.GAMEOVER && (
        <div className="text-center max-w-xl animate-in zoom-in duration-500">
          <div className="mb-6 p-10 bg-slate-900/90 border-4 border-red-500 rounded-3xl shadow-[0_0_50px_rgba(239,68,68,0.4)]">
            <h2 className="text-5xl font-orbitron font-black text-red-500 mb-2 italic">CALCULATION ERROR</h2>
            <p className="text-slate-400 font-orbitron mb-8 tracking-widest">SYSTEM OVERLOAD AT {stats.score} POINTS</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Max Level</div>
                <div className="text-2xl font-orbitron font-bold text-cyan-400">{stats.level}</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Final Score</div>
                <div className="text-2xl font-orbitron font-bold text-pink-500">{stats.score}</div>
              </div>
            </div>

            {mathFact && (
              <div className="bg-cyan-500/10 border-l-4 border-cyan-400 p-4 mb-8 text-left italic">
                <p className="text-sm text-cyan-100">" {mathFact} "</p>
              </div>
            )}

            <div className="flex flex-col gap-3">
              <NeonButton onClick={startGame} className="w-full">
                <div className="flex items-center justify-center gap-2">
                  <RotateCcw size={20} />
                  REBOOT CORE
                </div>
              </NeonButton>
              <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">
                COMMAND CENTER
              </NeonButton>
            </div>
          </div>
        </div>
      )}

      {/* Leaderboard Screen */}
      {gameState === GameState.LEADERBOARD && (
        <div className="w-full max-w-2xl bg-slate-900/90 border-2 border-purple-500 p-8 rounded-2xl shadow-[0_0_40px_rgba(168,85,247,0.3)] backdrop-blur-xl animate-in slide-in-from-right-10 duration-500">
          <div className="flex items-center gap-4 mb-8 border-b border-purple-500/30 pb-4">
            <Trophy className="text-purple-500 w-10 h-10" />
            <h2 className="text-4xl font-orbitron font-black text-purple-500">HALL OF LOGIC</h2>
          </div>

          <div className="space-y-3 mb-8 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {leaderboard.length > 0 ? leaderboard.map((entry, idx) => (
              <div key={idx} className="flex justify-between items-center p-4 bg-slate-800/50 border border-slate-700 rounded-lg group hover:border-purple-400 transition-all">
                <div className="flex items-center gap-4">
                  <span className={`font-orbitron font-bold text-lg w-8 ${idx < 3 ? 'text-yellow-400' : 'text-slate-500'}`}>#{idx + 1}</span>
                  <div>
                    <div className="font-bold text-slate-200">{entry.name}</div>
                    <div className="text-xs text-slate-500 font-orbitron uppercase">Level {entry.level}</div>
                  </div>
                </div>
                <div className="text-xl font-orbitron font-black text-purple-400">{entry.score}</div>
              </div>
            )) : (
              <div className="text-center py-10 text-slate-500 italic">No records found. Become the first legend.</div>
            )}
          </div>

          <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">
            BACK TO DASHBOARD
          </NeonButton>
        </div>
      )}

      {/* Background Decor - Geometry Dash Style Particles */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden -z-10 opacity-30">
        <div className="absolute top-1/4 left-1/4 w-32 h-32 border border-cyan-400 rotate-45 animate-pulse-fast"></div>
        <div className="absolute bottom-1/4 right-1/4 w-48 h-48 border border-pink-500 -rotate-12 animate-pulse"></div>
        <div className="absolute top-10 right-20 w-16 h-16 border-t-2 border-r-2 border-purple-500 rotate-[135deg]"></div>
        <div className="absolute bottom-10 left-20 w-24 h-2 bg-cyan-400/20 blur-sm"></div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, MathProblem, PlayerStats, LeaderboardEntry } from './types';
import { LEVELS, INITIAL_STATS } from './constants';
import { getEncouragement, getMathFact } from './services/geminiService';
import NeonButton from './components/NeonButton';
import GameCard from './components/GameCard';
import { Trophy, Zap, Clock, Star, BrainCircuit, RotateCcw, Play, BarChart2 } from 'lucide-react';

const App: React.FC = () => {
  // Game State
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS);
  const [currentProblem, setCurrentProblem] = useState<MathProblem | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [combo, setCombo] = useState<number>(0);
  const [feedback, setFeedback] = useState<string>('');
  const [mathFact, setMathFact] = useState<string>('');
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [isAnswering, setIsAnswering] = useState<boolean>(false);
  const [shaking, setShaking] = useState<boolean>(false);

  // Fix: Replace NodeJS.Timeout with ReturnType<typeof setTimeout> to resolve "Cannot find namespace 'NodeJS'" in browser environments
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Load Leaderboard
  useEffect(() => {
    const saved = localStorage.getItem('mathdash_leaderboard');
    if (saved) setLeaderboard(JSON.parse(saved));
  }, []);

  // Generate Problem based on level
  const generateProblem = useCallback(() => {
    const config = LEVELS[stats.level - 1];
    const op = config.operations[Math.floor(Math.random() * config.operations.length)];
    let n1, n2, answer;

    if (op === '*') {
      n1 = Math.floor(Math.random() * 5) + 1; // 1-5
      n2 = Math.floor(Math.random() * 10) + 1; // 1-10
      answer = n1 * n2;
    } else if (op === '-') {
      n1 = Math.floor(Math.random() * config.maxNumber) + 5;
      n2 = Math.floor(Math.random() * n1);
      answer = n1 - n2;
    } else {
      n1 = Math.floor(Math.random() * config.maxNumber);
      n2 = Math.floor(Math.random() * config.maxNumber);
      answer = n1 + n2;
    }

    const options = new Set<number>();
    options.add(answer);
    while (options.size < 4) {
      const offset = Math.floor(Math.random() * 10) - 5;
      const fake = Math.max(0, answer + (offset === 0 ? 3 : offset));
      options.add(fake);
    }

    const problem: MathProblem = {
      id: Math.random().toString(36).substr(2, 9),
      question: `${n1} ${op === '*' ? '×' : op} ${n2}`,
      answer,
      options: Array.from(options).sort(() => Math.random() - 0.5),
      difficulty: stats.level
    };

    setCurrentProblem(problem);
    setTimeLeft(config.timeLimit);
    setIsAnswering(false);
  }, [stats.level]);

  // Start Game
  const startGame = () => {
    setStats(INITIAL_STATS);
    setGameState(GameState.PLAYING);
    setCombo(0);
    generateProblem();
  };

  // Timer logic
  useEffect(() => {
    if (gameState === GameState.PLAYING && timeLeft > 0 && !isAnswering) {
      timerRef.current = setTimeout(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && gameState === GameState.PLAYING && !isAnswering) {
      handleAnswer(-1); // Fail due to time
    }
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [timeLeft, gameState, isAnswering]);

  // Handle Answer
  const handleAnswer = async (selected: number) => {
    if (!currentProblem || isAnswering) return;

    setIsAnswering(true);
    const isCorrect = selected === currentProblem.answer;

    if (isCorrect) {
      const newCombo = combo + 1;
      setCombo(newCombo);
      const points = 10 * stats.level * (newCombo > 5 ? 2 : 1);

      setStats(prev => {
        const newExp = prev.experience + 10;
        const config = LEVELS[prev.level - 1];

        // Level Up Check
        if (newExp >= config.targetExp && prev.level < LEVELS.length) {
          return {
            ...prev,
            score: prev.score + points,
            experience: 0,
            level: prev.level + 1
          };
        }

        return {
          ...prev,
          score: prev.score + points,
          experience: newExp
        };
      });

      // AI Commentary for streaks
      if (newCombo % 5 === 0) {
        const msg = await getEncouragement(newCombo, stats.level);
        setFeedback(msg);
        setTimeout(() => setFeedback(''), 2000);
      }

      // Progress to next problem
      setTimeout(() => {
        generateProblem();
      }, 400);

    } else {
      setShaking(true);
      setCombo(0);
      setStats(prev => ({
        ...prev,
        highScore: Math.max(prev.highScore, prev.score)
      }));

      setTimeout(() => setShaking(false), 500);

      // End game on mistake (Geometry Dash style: one crash and you're done)
      setGameState(GameState.GAMEOVER);

      // Update leaderboard
      const newEntry: LeaderboardEntry = {
        name: "PLAYER_" + Math.floor(Math.random() * 999),
        score: stats.score,
        level: stats.level,
        date: new Date().toLocaleDateString()
      };
      const updatedLeaderboard = [...leaderboard, newEntry]
        .sort((a, b) => b.score - a.score)
        .slice(0, 10);
      setLeaderboard(updatedLeaderboard);
      localStorage.setItem('mathdash_leaderboard', JSON.stringify(updatedLeaderboard));

      // Load a fun math fact for the death screen
      const fact = await getMathFact(stats.level);
      setMathFact(fact);
    }
  };

  // UI Components
  const ProgressBar = () => {
    const config = LEVELS[stats.level - 1];
    const percentage = (stats.experience / config.targetExp) * 100;
    return (
      <div className="w-full bg-slate-800 h-4 rounded-full border border-slate-700 overflow-hidden mb-8">
        <div 
          className="h-full bg-cyan-400 shadow-[0_0_15px_rgba(34,211,238,0.8)] transition-all duration-500" 
          style={{ width: `${percentage}%` }}
        />
      </div>
    );
  };

  return (
    <div className={`min-h-screen bg-[#0f172a] bg-grid text-white flex flex-col items-center justify-center p-6 ${shaking ? 'animate-bounce' : ''}`}>

      {/* HUD - Always visible during play */}
      {gameState === GameState.PLAYING && (
        <div className="fixed top-0 left-0 w-full p-6 flex justify-between items-start z-10">
          <div className="flex flex-col gap-2">
            <div className="flex items-center gap-2 bg-slate-900/80 border border-cyan-400 p-3 rounded-lg backdrop-blur-md">
              <Zap className="text-cyan-400 w-5 h-5 fill-cyan-400" />
              <span className="font-orbitron font-bold text-xl">{stats.score}</span>
            </div>
            <div className="text-sm font-orbitron text-pink-400 uppercase tracking-widest px-1">
              COMBO x{combo}
            </div>
          </div>

          <div className="flex flex-col items-center gap-2">
            <h1 className="font-orbitron font-black text-2xl tracking-tighter neon-text-cyan">
              {LEVELS[stats.level - 1].title}
            </h1>
            <div className="w-64">
              <ProgressBar />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className={`flex items-center gap-2 bg-slate-900/80 border p-3 rounded-lg backdrop-blur-md ${timeLeft < 5 ? 'border-red-500 animate-pulse' : 'border-cyan-400'}`}>
              <Clock className={`w-5 h-5 ${timeLeft < 5 ? 'text-red-500' : 'text-cyan-400'}`} />
              <span className="font-orbitron font-bold text-xl">{timeLeft}s</span>
            </div>
          </div>
        </div>
      )}

      {/* Start Screen */}
      {gameState === GameState.START && (
        <div className="text-center max-w-2xl animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="mb-8 relative inline-block">
             <div className="w-24 h-24 border-4 border-cyan-400 bg-cyan-400/10 rotate-45 mx-auto mb-6 flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.4)]">
                <BrainCircuit className="w-12 h-12 text-cyan-400 -rotate-45" />
             </div>
             <h1 className="text-7xl font-orbitron font-black mb-4 tracking-tighter neon-text-cyan italic">
               MATH<span className="text-pink-500">DASH</span>
             </h1>
             <p className="text-slate-400 font-orbitron tracking-widest uppercase">Neon Logic Engine 3.0</p>
          </div>

          <div className="flex flex-col gap-4 items-center">
            <NeonButton onClick={startGame} className="w-full sm:w-64 text-xl">
              <div className="flex items-center justify-center gap-2">
                <Play className="fill-current" />
                INITIATE
              </div>
            </NeonButton>
            <NeonButton 
              variant="purple" 
              onClick={() => setGameState(GameState.LEADERBOARD)} 
              className="w-full sm:w-64"
            >
              <div className="flex items-center justify-center gap-2">
                <Trophy size={18} />
                ARCHIVES
              </div>
            </NeonButton>
          </div>
        </div>
      )}

      {/* Game Play */}
      {gameState === GameState.PLAYING && currentProblem && (
        <div className="relative">
          {feedback && (
            <div className="absolute -top-20 left-1/2 -translate-x-1/2 w-full text-center pointer-events-none animate-bounce">
              <h2 className="text-4xl font-orbitron font-black text-pink-500 italic neon-text-pink drop-shadow-lg">
                {feedback}
              </h2>
            </div>
          )}
          <GameCard 
            problem={currentProblem} 
            onAnswer={handleAnswer} 
            isLocked={isAnswering} 
          />
        </div>
      )}

      {/* Game Over Screen */}
      {gameState === GameState.GAMEOVER && (
        <div className="text-center max-w-xl animate-in zoom-in duration-500">
          <div className="mb-6 p-10 bg-slate-900/90 border-4 border-red-500 rounded-3xl shadow-[0_0_50px_rgba(239,68,68,0.4)]">
            <h2 className="text-5xl font-orbitron font-black text-red-500 mb-2 italic">CALCULATION ERROR</h2>
            <p className="text-slate-400 font-orbitron mb-8 tracking-widest">SYSTEM OVERLOAD AT {stats.score} POINTS</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Max Level</div>
                <div className="text-2xl font-orbitron font-bold text-cyan-400">{stats.level}</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Final Score</div>
                <div className="text-2xl font-orbitron font-bold text-pink-500">{stats.score}</div>
              </div>
            </div>

            {mathFact && (
              <div className="bg-cyan-500/10 border-l-4 border-cyan-400 p-4 mb-8 text-left italic">
                <p className="text-sm text-cyan-100">" {mathFact} "</p>
              </div>
            )}

            <div className="flex flex-col gap-3">
              <NeonButton onClick={startGame} className="w-full">
                <div className="flex items-center justify-center gap-2">
                  <RotateCcw size={20} />
                  REBOOT CORE
                </div>
              </NeonButton>
              <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">
                COMMAND CENTER
              </NeonButton>
            </div>
          </div>
        </div>
      )}

      {/* Leaderboard Screen */}
      {gameState === GameState.LEADERBOARD && (
        <div className="w-full max-w-2xl bg-slate-900/90 border-2 border-purple-500 p-8 rounded-2xl shadow-[0_0_40px_rgba(168,85,247,0.3)] backdrop-blur-xl animate-in slide-in-from-right-10 duration-500">
          <div className="flex items-center gap-4 mb-8 border-b border-purple-500/30 pb-4">
            <Trophy className="text-purple-500 w-10 h-10" />
            <h2 className="text-4xl font-orbitron font-black text-purple-500">HALL OF LOGIC</h2>
          </div>

          <div className="space-y-3 mb-8 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {leaderboard.length > 0 ? leaderboard.map((entry, idx) => (
              <div key={idx} className="flex justify-between items-center p-4 bg-slate-800/50 border border-slate-700 rounded-lg group hover:border-purple-400 transition-all">
                <div className="flex items-center gap-4">
                  <span className={`font-orbitron font-bold text-lg w-8 ${idx < 3 ? 'text-yellow-400' : 'text-slate-500'}`}>#{idx + 1}</span>
                  <div>
                    <div className="font-bold text-slate-200">{entry.name}</div>
                    <div className="text-xs text-slate-500 font-orbitron uppercase">Level {entry.level}</div>
                  </div>
                </div>
                <div className="text-xl font-orbitron font-black text-purple-400">{entry.score}</div>
              </div>
            )) : (
              <div className="text-center py-10 text-slate-500 italic">No records found. Become the first legend.</div>
            )}
          </div>

          <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">
            BACK TO DASHBOARD
          </NeonButton>
        </div>
      )}

      {/* Background Decor - Geometry Dash Style Particles */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden -z-10 opacity-30">
        <div className="absolute top-1/4 left-1/4 w-32 h-32 border border-cyan-400 rotate-45 animate-pulse-fast"></div>
        <div className="absolute bottom-1/4 right-1/4 w-48 h-48 border border-pink-500 -rotate-12 animate-pulse"></div>
        <div className="absolute top-10 right-20 w-16 h-16 border-t-2 border-r-2 border-purple-500 rotate-[135deg]"></div>
        <div className="absolute bottom-10 left-20 w-24 h-2 bg-cyan-400/20 blur-sm"></div>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getEncouragement = async (combo: number, level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The player is 8 years old. They just hit a combo of ${combo} in Level ${level}. Give a very short, high-energy 2-3 word phrase in the style of "Geometry Dash" or a cool game announcer. Examples: "UNSTOPPABLE!", "PURE SKILL!", "NEON MASTER!".`,
      config: {
        // Fix: Added thinkingBudget as required by @google/genai guidelines when setting maxOutputTokens
        maxOutputTokens: 20,
        thinkingConfig: { thinkingBudget: 10 },
      }
    });
    return response.text.trim().toUpperCase() || "AMAZING!";
  } catch (error) {
    return "GREAT JOB!";
  }
};

export const getMathFact = async (level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Give a fun, short math fact for an 8-year-old child that relates to level ${level} concepts (Addition/Subtraction/Logic). Keep it simple and encouraging. Maximum 15 words.`,
      config: {
        // Fix: Added thinkingBudget as required by @google/genai guidelines when setting maxOutputTokens
        maxOutputTokens: 50,
        thinkingConfig: { thinkingBudget: 25 },
      }
    });
    return response.text.trim();
  } catch (error) {
    return "Math is the language of the universe!";
  }
};

export enum GameState {
  START = 'START',
  MODE_SELECT = 'MODE_SELECT',
  PLAYING = 'PLAYING',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  GAMEOVER = 'GAMEOVER',
  LEADERBOARD = 'LEADERBOARD'
}

export enum GameMode {
  CLASSIC = 'CLASSIC',
  BLITZ = 'BLITZ',
  ZEN = 'ZEN'
}

export interface MathProblem {
  id: string;
  question: string;
  answer: number;
  options: number[];
  difficulty: number;
}

export interface PlayerStats {
  score: number;
  level: number;
  experience: number;
  highScore: number;
  combos: number;
  totalSolved: number;
}

export interface LeaderboardEntry {
  name: string;
  score: number;
  level: number;
  mode: GameMode;
  date: string;
}

export interface LevelConfig {
  title: string;
  description: string;
  targetExp: number;
  operations: ('+' | '-' | '*')[];
  maxNumber: number;
  timeLimit: number;
}

import { LevelConfig, PlayerStats } from './types';

export const LEVELS: LevelConfig[] = [
  {
    title: "Level 1: Genesis",
    description: "Addition within 10. Simple and clean.",
    targetExp: 100,
    operations: ['+'],
    maxNumber: 10,
    timeLimit: 10,
  },
  {
    title: "Level 2: Pulse",
    description: "Subtraction steps in. Stay sharp.",
    targetExp: 250,
    operations: ['+', '-'],
    maxNumber: 15,
    timeLimit: 12,
  },
  {
    title: "Level 3: Velocity",
    description: "Faster responses needed. Numbers up to 20.",
    targetExp: 500,
    operations: ['+', '-'],
    maxNumber: 20,
    timeLimit: 10,
  },
  {
    title: "Level 4: Electron",
    description: "Addition of double digits.",
    targetExp: 800,
    operations: ['+', '-'],
    maxNumber: 50,
    timeLimit: 15,
  },
  {
    title: "Level 5: Multiplication X",
    description: "Introduction to simple multiplication (2, 5, 10).",
    targetExp: 1200,
    operations: ['*', '+'],
    maxNumber: 10, 
    timeLimit: 20,
  },
  {
    title: "Level 6: Overdrive",
    description: "Mixed operations at high speed.",
    targetExp: 2000,
    operations: ['+', '-', '*'],
    maxNumber: 100,
    timeLimit: 12,
  }
];

export const INITIAL_STATS: PlayerStats = {
  score: 0,
  level: 1,
  experience: 0,
  highScore: 0,
  combos: 0,
  totalSolved: 0
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GameMode, MathProblem, PlayerStats, LeaderboardEntry } from './types';
import { LEVELS, INITIAL_STATS } from './constants';
import { getEncouragement, getMathFact } from './services/geminiService';
import NeonButton from './components/NeonButton';
import GameCard from './components/GameCard';
import { Trophy, Zap, Clock, Star, BrainCircuit, RotateCcw, Play, Infinity as InfinityIcon, Timer, Info } from 'lucide-react';

const App: React.FC = () => {
  // Game State
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [gameMode, setGameMode] = useState<GameMode>(GameMode.CLASSIC);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS);
  const [currentProblem, setCurrentProblem] = useState<MathProblem | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [globalTimeLeft, setGlobalTimeLeft] = useState<number>(60);
  const [combo, setCombo] = useState<number>(0);
  const [feedback, setFeedback] = useState<string>('');
  const [mathFact, setMathFact] = useState<string>('');
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [isAnswering, setIsAnswering] = useState<boolean>(false);
  const [shaking, setShaking] = useState<boolean>(false);

  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Load Leaderboard
  useEffect(() => {
    const saved = localStorage.getItem('mathdash_leaderboard_v2');
    if (saved) setLeaderboard(JSON.parse(saved));
  }, []);

  // Generate Problem based on level
  const generateProblem = useCallback(() => {
    const levelIdx = Math.min(stats.level - 1, LEVELS.length - 1);
    const config = LEVELS[levelIdx];
    const op = config.operations[Math.floor(Math.random() * config.operations.length)];
    let n1, n2, answer;

    if (op === '*') {
      n1 = Math.floor(Math.random() * 5) + 1;
      n2 = Math.floor(Math.random() * 10) + 1;
      answer = n1 * n2;
    } else if (op === '-') {
      n1 = Math.floor(Math.random() * config.maxNumber) + 5;
      n2 = Math.floor(Math.random() * n1);
      answer = n1 - n2;
    } else {
      n1 = Math.floor(Math.random() * config.maxNumber);
      n2 = Math.floor(Math.random() * config.maxNumber);
      answer = n1 + n2;
    }

    const options = new Set<number>();
    options.add(answer);
    while (options.size < 4) {
      const offset = Math.floor(Math.random() * 10) - 5;
      const fake = Math.max(0, answer + (offset === 0 ? 3 : offset));
      options.add(fake);
    }

    const problem: MathProblem = {
      id: Math.random().toString(36).substr(2, 9),
      question: `${n1} ${op === '*' ? '×' : op} ${n2}`,
      answer,
      options: Array.from(options).sort(() => Math.random() - 0.5),
      difficulty: stats.level
    };

    setCurrentProblem(problem);
    setTimeLeft(config.timeLimit);
    setIsAnswering(false);
  }, [stats.level]);

  // Start Game with specific mode
  const startGame = (mode: GameMode) => {
    setGameMode(mode);
    setStats(INITIAL_STATS);
    setGameState(GameState.PLAYING);
    setCombo(0);
    setGlobalTimeLeft(60); // Reset for Blitz
    generateProblem();
  };

  // Timer logic
  useEffect(() => {
    if (gameState !== GameState.PLAYING || isAnswering) return;

    if (gameMode === GameMode.CLASSIC) {
      if (timeLeft > 0) {
        timerRef.current = setTimeout(() => setTimeLeft(prev => prev - 1), 1000);
      } else {
        handleAnswer(-1); // Death by time in Classic
      }
    } else if (gameMode === GameMode.BLITZ) {
      if (globalTimeLeft > 0) {
        timerRef.current = setTimeout(() => setGlobalTimeLeft(prev => prev - 1), 1000);
      } else {
        setGameState(GameState.GAMEOVER);
      }
    }

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [timeLeft, globalTimeLeft, gameState, isAnswering, gameMode]);

  // Handle Answer
  const handleAnswer = async (selected: number) => {
    if (!currentProblem || isAnswering) return;

    setIsAnswering(true);
    const isCorrect = selected === currentProblem.answer;

    if (isCorrect) {
      const newCombo = combo + 1;
      setCombo(newCombo);
      const points = 10 * stats.level * (newCombo > 5 ? 2 : 1);

      setStats(prev => {
        const nextSolved = prev.totalSolved + 1;
        const newExp = prev.experience + 10;
        const currentLevelConfig = LEVELS[Math.min(prev.level - 1, LEVELS.length - 1)];

        let nextLevel = prev.level;
        let nextExp = newExp;

        // Blitz & Zen scale level based on total solved
        if (gameMode !== GameMode.CLASSIC) {
           if (nextSolved % 8 === 0 && nextLevel < LEVELS.length) {
             nextLevel++;
           }
        } else if (newExp >= currentLevelConfig.targetExp && prev.level < LEVELS.length) {
          nextLevel++;
          nextExp = 0;
        }

        return {
          ...prev,
          score: prev.score + points,
          experience: nextExp,
          level: nextLevel,
          totalSolved: nextSolved
        };
      });

      if (newCombo % 5 === 0) {
        getEncouragement(newCombo, stats.level).then(setFeedback);
        setTimeout(() => setFeedback(''), 1500);
      }

      setTimeout(() => generateProblem(), 300);

    } else {
      setShaking(true);
      setCombo(0);

      if (gameMode === GameMode.CLASSIC) {
        // One hit death
        setGameState(GameState.GAMEOVER);
        finalizeGame();
      } else if (gameMode === GameMode.BLITZ) {
        // Penalty but keep going
        setGlobalTimeLeft(prev => Math.max(0, prev - 3));
        setTimeout(() => {
          setShaking(false);
          setIsAnswering(false);
          generateProblem();
        }, 500);
      } else if (gameMode === GameMode.ZEN) {
        // No penalty, just next problem
        setTimeout(() => {
          setShaking(false);
          setIsAnswering(false);
          generateProblem();
        }, 500);
      }
    }
  };

  const finalizeGame = async () => {
    const newEntry: LeaderboardEntry = {
      name: "DASH_ACE_" + Math.floor(Math.random() * 999),
      score: stats.score,
      level: stats.level,
      mode: gameMode,
      date: new Date().toLocaleDateString()
    };
    const updated = [...leaderboard, newEntry].sort((a, b) => b.score - a.score).slice(0, 10);
    setLeaderboard(updated);
    localStorage.setItem('mathdash_leaderboard_v2', JSON.stringify(updated));
    setMathFact(await getMathFact(stats.level));
  };

  return (
    <div className={`min-h-screen bg-[#0f172a] bg-grid text-white flex flex-col items-center justify-center p-6 ${shaking ? 'animate-pulse' : ''}`}>

      {/* HUD */}
      {gameState === GameState.PLAYING && (
        <div className="fixed top-0 left-0 w-full p-6 flex justify-between items-start z-10">
          <div className="flex flex-col gap-2">
            <div className="flex items-center gap-2 bg-slate-900/80 border border-cyan-400 p-3 rounded-lg backdrop-blur-md">
              <Zap className="text-cyan-400 w-5 h-5 fill-cyan-400" />
              <span className="font-orbitron font-bold text-xl">{stats.score}</span>
            </div>
            {gameMode !== GameMode.ZEN && (
              <div className="text-sm font-orbitron text-pink-400 uppercase tracking-widest px-1 animate-pulse">
                COMBO x{combo}
              </div>
            )}
          </div>

          <div className="flex flex-col items-center gap-2">
            <h1 className="font-orbitron font-black text-2xl tracking-tighter neon-text-cyan uppercase">
              {gameMode} MODE {gameMode === GameMode.CLASSIC ? `- LVL ${stats.level}` : ''}
            </h1>
            <div className="text-xs text-slate-400 font-orbitron">SOLVED: {stats.totalSolved}</div>
          </div>

          <div className="flex items-center gap-4">
            {gameMode === GameMode.CLASSIC && (
              <div className={`flex items-center gap-2 bg-slate-900/80 border p-3 rounded-lg backdrop-blur-md ${timeLeft < 4 ? 'border-red-500 animate-pulse' : 'border-cyan-400'}`}>
                <Clock className={`w-5 h-5 ${timeLeft < 4 ? 'text-red-500' : 'text-cyan-400'}`} />
                <span className="font-orbitron font-bold text-xl">{timeLeft}s</span>
              </div>
            )}
            {gameMode === GameMode.BLITZ && (
               <div className={`flex items-center gap-2 bg-slate-900/80 border p-3 rounded-lg backdrop-blur-md ${globalTimeLeft < 10 ? 'border-red-500 animate-pulse' : 'border-pink-500'}`}>
                <Timer className={`w-5 h-5 ${globalTimeLeft < 10 ? 'text-red-500' : 'text-pink-500'}`} />
                <span className="font-orbitron font-bold text-xl">{globalTimeLeft}s</span>
              </div>
            )}
            {gameMode === GameMode.ZEN && (
               <div className="flex items-center gap-2 bg-slate-900/80 border border-green-400 p-3 rounded-lg backdrop-blur-md">
                <InfinityIcon className="w-5 h-5 text-green-400" />
                <span className="font-orbitron font-bold text-xl">NO LIMIT</span>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Mode Select & Start */}
      {gameState === GameState.START && (
        <div className="text-center max-w-4xl animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="mb-12 relative inline-block">
             <div className="w-20 h-20 border-4 border-cyan-400 bg-cyan-400/10 rotate-45 mx-auto mb-6 flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.4)]">
                <BrainCircuit className="w-10 h-10 text-cyan-400 -rotate-45" />
             </div>
             <h1 className="text-8xl font-orbitron font-black mb-2 tracking-tighter neon-text-cyan italic">
               MATH<span className="text-pink-500">DASH</span>
             </h1>
             <p className="text-slate-500 font-orbitron tracking-[0.3em] uppercase text-sm">Synthetic Learning Protocol</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
            <div className="bg-slate-900/50 border-2 border-cyan-400 p-6 rounded-2xl flex flex-col items-center hover:bg-cyan-400/5 transition-all">
              <Zap className="text-cyan-400 mb-4" size={40} />
              <h3 className="font-orbitron font-bold text-xl mb-2">NEON CLASSIC</h3>
              <p className="text-xs text-slate-400 mb-6 uppercase tracking-wider">Leveling System. One hit death. True skill test.</p>
              <NeonButton variant="cyan" onClick={() => startGame(GameMode.CLASSIC)} className="w-full">RUN</NeonButton>
            </div>

            <div className="bg-slate-900/50 border-2 border-pink-400 p-6 rounded-2xl flex flex-col items-center hover:bg-pink-400/5 transition-all">
              <Timer className="text-pink-400 mb-4" size={40} />
              <h3 className="font-orbitron font-bold text-xl mb-2">BLITZ RUSH</h3>
              <p className="text-xs text-slate-400 mb-6 uppercase tracking-wider">60 seconds. High pressure. Infinite potential.</p>
              <NeonButton variant="pink" onClick={() => startGame(GameMode.BLITZ)} className="w-full">SPRINT</NeonButton>
            </div>

            <div className="bg-slate-900/50 border-2 border-green-400 p-6 rounded-2xl flex flex-col items-center hover:bg-green-400/5 transition-all">
              <InfinityIcon className="text-green-400 mb-4" size={40} />
              <h3 className="font-orbitron font-bold text-xl mb-2">ZEN FLOW</h3>
              <p className="text-xs text-slate-400 mb-6 uppercase tracking-wider">No death. No timers. Perfect for training.</p>
              <NeonButton variant="purple" onClick={() => startGame(GameMode.ZEN)} className="w-full">FLOW</NeonButton>
            </div>
          </div>

          <div className="flex gap-4 justify-center">
            <button onClick={() => setGameState(GameState.LEADERBOARD)} className="text-slate-500 font-orbitron uppercase text-xs hover:text-white transition-all flex items-center gap-2">
              <Trophy size={14} /> View Hall of Fame
            </button>
          </div>
        </div>
      )}

      {/* Game Play */}
      {gameState === GameState.PLAYING && currentProblem && (
        <div className="relative">
          {feedback && (
            <div className="absolute -top-24 left-1/2 -translate-x-1/2 w-full text-center pointer-events-none animate-bounce">
              <h2 className="text-5xl font-orbitron font-black text-pink-500 italic neon-text-pink">
                {feedback}
              </h2>
            </div>
          )}
          <GameCard 
            problem={currentProblem} 
            onAnswer={handleAnswer} 
            isLocked={isAnswering} 
          />
          {gameMode === GameMode.ZEN && (
            <div className="mt-8">
              <NeonButton variant="purple" onClick={() => setGameState(GameState.START)}>QUIT FLOW</NeonButton>
            </div>
          )}
        </div>
      )}

      {/* Game Over */}
      {gameState === GameState.GAMEOVER && (
        <div className="text-center max-w-xl animate-in zoom-in duration-500">
          <div className="mb-6 p-10 bg-slate-900/90 border-4 border-red-500 rounded-3xl shadow-[0_0_50px_rgba(239,68,68,0.4)]">
            <h2 className="text-5xl font-orbitron font-black text-red-500 mb-2 italic">DASH TERMINATED</h2>
            <p className="text-slate-400 font-orbitron mb-8 tracking-widest">MODE: {gameMode} | SCORE: {stats.score}</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Solved</div>
                <div className="text-2xl font-orbitron font-bold text-cyan-400">{stats.totalSolved}</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                <div className="text-xs text-slate-500 uppercase font-orbitron mb-1">Max Level</div>
                <div className="text-2xl font-orbitron font-bold text-pink-500">{stats.level}</div>
              </div>
            </div>

            {mathFact && (
              <div className="bg-cyan-500/10 border-l-4 border-cyan-400 p-4 mb-8 text-left italic rounded">
                <p className="text-sm text-cyan-100"><Info className="inline mr-2" size={16} /> {mathFact}</p>
              </div>
            )}

            <div className="flex flex-col gap-3">
              <NeonButton onClick={() => startGame(gameMode)} className="w-full">
                RETRY DASH
              </NeonButton>
              <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">
                MENU
              </NeonButton>
            </div>
          </div>
        </div>
      )}

      {/* Hall of Fame */}
      {gameState === GameState.LEADERBOARD && (
        <div className="w-full max-w-2xl bg-slate-900/90 border-2 border-purple-500 p-8 rounded-2xl shadow-[0_0_40px_rgba(168,85,247,0.3)] backdrop-blur-xl animate-in slide-in-from-right-10 duration-500">
          <div className="flex items-center gap-4 mb-8 border-b border-purple-500/30 pb-4">
            <Trophy className="text-purple-500 w-10 h-10" />
            <h2 className="text-4xl font-orbitron font-black text-purple-500 italic">LOGIC ARCHIVES</h2>
          </div>

          <div className="space-y-3 mb-8 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {leaderboard.map((entry, idx) => (
              <div key={idx} className="flex justify-between items-center p-4 bg-slate-800/50 border border-slate-700 rounded-lg">
                <div className="flex items-center gap-4">
                  <span className={`font-orbitron font-bold text-lg w-8 ${idx < 3 ? 'text-yellow-400' : 'text-slate-500'}`}>#{idx + 1}</span>
                  <div>
                    <div className="font-bold text-slate-200">{entry.name}</div>
                    <div className="text-[10px] text-slate-500 font-orbitron uppercase tracking-widest">{entry.mode} • LVL {entry.level}</div>
                  </div>
                </div>
                <div className="text-xl font-orbitron font-black text-purple-400">{entry.score}</div>
              </div>
            ))}
          </div>

          <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">BACK</NeonButton>
        </div>
      )}
    </div>
  );
};

export default App;

export enum GameState {
  START = 'START',
  MODE_SELECT = 'MODE_SELECT',
  PLAYING = 'PLAYING',
  GAMEOVER = 'GAMEOVER',
  LEADERBOARD = 'LEADERBOARD'
}

export enum GameMode {
  CLASSIC = 'CLASSIC',
  BLITZ = 'BLITZ',
  ZEN = 'ZEN',
  DUEL = 'DUEL'
}

export type AgeBracket = 6 | 7 | 8 | 9 | 10;

export interface Notification {
  id: string;
  message: string;
  type: 'success' | 'comment' | 'level';
}

export interface MathProblem {
  id: string;
  question: string;
  answer: number;
  options: number[];
  difficulty: number;
}

export interface PlayerStats {
  score: number;
  level: number;
  experience: number;
  highScore: number;
  combos: number;
  totalSolved: number;
  duelProgress: number;
  botProgress: number;
}

export interface LeaderboardEntry {
  name: string;
  score: number;
  level: number;
  mode: GameMode;
  date: string;
}

export interface LevelConfig {
  title: string;
  operations: ('+' | '-' | '*')[];
  maxNumber: number;
  timeLimit: number;
}

import { LevelConfig, PlayerStats, AgeBracket, LeaderboardEntry, GameMode } from './types';

export const GET_LEVELS = (age: AgeBracket): LevelConfig[] => {
  const baseMax = age * 5; // Age 6 = 30, Age 8 = 40, etc.
  return [
    { title: "Level 1: Genesis", operations: ['+'], maxNumber: Math.min(age + 4, 10), timeLimit: 15 },
    { title: "Level 2: Pulse", operations: ['+', '-'], maxNumber: age * 2, timeLimit: 12 },
    { title: "Level 3: Velocity", operations: ['+', '-'], maxNumber: age * 3, timeLimit: 10 },
    { title: "Level 4: Electron", operations: age >= 8 ? ['+', '-', '*'] : ['+', '-'], maxNumber: age * 4, timeLimit: 12 },
    { title: "Level 5: Supernova", operations: ['+', '-', '*'], maxNumber: age * 6, timeLimit: 10 },
  ];
};

export const INITIAL_STATS: PlayerStats = {
  score: 0,
  level: 1,
  experience: 0,
  highScore: 0,
  combos: 0,
  totalSolved: 0,
  duelProgress: 0,
  botProgress: 0
};

export const BOT_NAMES = ["NeonGhost", "CyberAce", "LogicDash", "BitRunner", "ZenMaster", "VoidLogic", "NovaKid"];
export const BOT_COMMENTS = [
  "This level is intense!",
  "Calculated.",
  "Almost failed that one!",
  "Pure logic.",
  "Neon power activated!",
  "Who's top of the board?",
  "Keep dashing!"
];

export const INITIAL_LEADERBOARD: LeaderboardEntry[] = [
  { name: "NeonGhost", score: 2500, level: 5, mode: GameMode.CLASSIC, date: "2024-05-20" },
  { name: "CyberAce", score: 1800, level: 4, mode: GameMode.BLITZ, date: "2024-05-21" },
  { name: "LogicDash", score: 1200, level: 3, mode: GameMode.DUEL, date: "2024-05-19" }
];

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GameMode, MathProblem, PlayerStats, LeaderboardEntry, AgeBracket, Notification } from './types';
import { GET_LEVELS, INITIAL_STATS, BOT_NAMES, BOT_COMMENTS, INITIAL_LEADERBOARD } from './constants';
import { getEncouragement, getMathFact } from './services/geminiService';
import NeonButton from './components/NeonButton';
import GameCard from './components/GameCard';
import { Trophy, Zap, Clock, BrainCircuit, RotateCcw, Play, Infinity as InfinityIcon, Timer, Info, Users, MessageSquare } from 'lucide-react';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [gameMode, setGameMode] = useState<GameMode>(GameMode.CLASSIC);
  const [age, setAge] = useState<AgeBracket>(8);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS);
  const [currentProblem, setCurrentProblem] = useState<MathProblem | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [globalTimeLeft, setGlobalTimeLeft] = useState<number>(60);
  const [combo, setCombo] = useState<number>(0);
  const [feedback, setFeedback] = useState<string>('');
  const [mathFact, setMathFact] = useState<string>('');
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>(INITIAL_LEADERBOARD);
  const [isAnswering, setIsAnswering] = useState<boolean>(false);
  const [shaking, setShaking] = useState<boolean>(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const levels = GET_LEVELS(age);

  useEffect(() => {
    const saved = localStorage.getItem('mathdash_v3_leaderboard');
    if (saved) setLeaderboard(JSON.parse(saved));
  }, []);

  // Notification Generator (Simulating live activity)
  useEffect(() => {
    const interval = setInterval(() => {
      const bot = BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)];
      const isComment = Math.random() > 0.7;
      const id = Math.random().toString(36).substr(2, 5);

      const newNotif: Notification = {
        id,
        message: isComment 
          ? `${bot}: ${BOT_COMMENTS[Math.floor(Math.random() * BOT_COMMENTS.length)]}`
          : `${bot} solved a Level ${Math.floor(Math.random() * 5) + 1} task!`,
        type: isComment ? 'comment' : 'success'
      };

      setNotifications(prev => [newNotif, ...prev].slice(0, 3));
      setTimeout(() => {
        setNotifications(prev => prev.filter(n => n.id !== id));
      }, 5000);
    }, 8000);
    return () => clearInterval(interval);
  }, []);

  // Duel Mode Logic: Bot Progress
  useEffect(() => {
    if (gameState === GameState.PLAYING && gameMode === GameMode.DUEL && !isAnswering) {
      const interval = setInterval(() => {
        setStats(prev => {
          const nextBot = prev.botProgress + 1.5; // Bot speed
          if (nextBot >= 100) {
            setGameState(GameState.GAMEOVER);
            return prev;
          }
          return { ...prev, botProgress: nextBot };
        });
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [gameState, gameMode, isAnswering]);

  const generateProblem = useCallback(() => {
    const levelIdx = Math.min(stats.level - 1, levels.length - 1);
    const config = levels[levelIdx];
    const op = config.operations[Math.floor(Math.random() * config.operations.length)];
    let n1, n2, answer;

    if (op === '*') {
      // Multiplication restricted by age
      n1 = Math.floor(Math.random() * (age >= 9 ? 9 : 5)) + 1;
      n2 = Math.floor(Math.random() * 10) + 1;
      answer = n1 * n2;
    } else if (op === '-') {
      n1 = Math.floor(Math.random() * config.maxNumber) + 5;
      n2 = Math.floor(Math.random() * n1);
      answer = n1 - n2;
    } else {
      n1 = Math.floor(Math.random() * config.maxNumber);
      n2 = Math.floor(Math.random() * config.maxNumber);
      answer = n1 + n2;
    }

    const options = new Set<number>();
    options.add(answer);
    while (options.size < 4) {
      const offset = Math.floor(Math.random() * 10) - 5;
      const fake = Math.max(0, answer + (offset === 0 ? 3 : offset));
      options.add(fake);
    }

    setCurrentProblem({
      id: Math.random().toString(36).substr(2, 9),
      question: `${n1} ${op === '*' ? '×' : op} ${n2}`,
      answer,
      options: Array.from(options).sort(() => Math.random() - 0.5),
      difficulty: stats.level
    });
    setTimeLeft(config.timeLimit);
    setIsAnswering(false);
  }, [stats.level, age, levels]);

  const startGame = (mode: GameMode) => {
    setGameMode(mode);
    setStats({ ...INITIAL_STATS, botProgress: 0, duelProgress: 0 });
    setGameState(GameState.PLAYING);
    setCombo(0);
    setGlobalTimeLeft(60);
    generateProblem();
  };

  useEffect(() => {
    if (gameState !== GameState.PLAYING || isAnswering) return;
    if (gameMode === GameMode.CLASSIC || gameMode === GameMode.DUEL) {
      if (timeLeft > 0) {
        timerRef.current = setTimeout(() => setTimeLeft(prev => prev - 1), 1000);
      } else if (gameMode === GameMode.CLASSIC) {
        handleAnswer(-1);
      }
    } else if (gameMode === GameMode.BLITZ) {
      if (globalTimeLeft > 0) {
        timerRef.current = setTimeout(() => setGlobalTimeLeft(prev => prev - 1), 1000);
      } else {
        setGameState(GameState.GAMEOVER);
      }
    }
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [timeLeft, globalTimeLeft, gameState, isAnswering, gameMode]);

  const handleAnswer = async (selected: number) => {
    if (!currentProblem || isAnswering) return;
    setIsAnswering(true);
    const isCorrect = selected === currentProblem.answer;

    if (isCorrect) {
      const newCombo = combo + 1;
      setCombo(newCombo);
      const points = 10 * stats.level;

      setStats(prev => {
        const nextSolved = prev.totalSolved + 1;
        let nextLevel = prev.level;
        let nextDuel = prev.duelProgress;

        if (gameMode === GameMode.DUEL) {
          nextDuel += 10;
          if (nextDuel >= 100) {
            setGameState(GameState.GAMEOVER);
            return prev;
          }
        }

        if (nextSolved % 5 === 0 && nextLevel < levels.length) nextLevel++;

        return {
          ...prev,
          score: prev.score + points,
          level: nextLevel,
          totalSolved: nextSolved,
          duelProgress: nextDuel
        };
      });

      if (newCombo % 5 === 0) {
        getEncouragement(newCombo, stats.level).then(setFeedback);
        setTimeout(() => setFeedback(''), 1500);
      }
      setTimeout(() => generateProblem(), 200);
    } else {
      setShaking(true);
      setCombo(0);
      if (gameMode === GameMode.CLASSIC || gameMode === GameMode.DUEL) {
        setGameState(GameState.GAMEOVER);
        finalizeGame();
      } else {
        setGlobalTimeLeft(prev => Math.max(0, prev - 3));
        setTimeout(() => { setShaking(false); setIsAnswering(false); generateProblem(); }, 500);
      }
    }
  };

  const finalizeGame = async () => {
    const name = "PLAYER_" + Math.floor(Math.random() * 999);
    const newEntry: LeaderboardEntry = {
      name, score: stats.score, level: stats.level, mode: gameMode, date: new Date().toLocaleDateString()
    };
    const updated = [...leaderboard, newEntry].sort((a, b) => b.score - a.score).slice(0, 10);
    setLeaderboard(updated);
    localStorage.setItem('mathdash_v3_leaderboard', JSON.stringify(updated));
    setMathFact(await getMathFact(stats.level));
  };

  return (
    <div className={`min-h-screen bg-[#0f172a] bg-grid text-white flex flex-col items-center justify-center p-6 ${shaking ? 'animate-pulse' : ''}`}>

      {/* Notifications Panel */}
      <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2 w-64">
        {notifications.map(n => (
          <div key={n.id} className="bg-slate-900/90 border-l-4 border-cyan-400 p-3 rounded shadow-lg animate-in slide-in-from-left duration-300 backdrop-blur-md flex items-start gap-3">
            {n.type === 'comment' ? <MessageSquare size={16} className="text-pink-400 mt-1" /> : <Users size={16} className="text-cyan-400 mt-1" />}
            <p className="text-xs font-orbitron text-slate-200">{n.message}</p>
          </div>
        ))}
      </div>

      {/* Start / Mode Select */}
      {gameState === GameState.START && (
        <div className="text-center max-w-4xl animate-in fade-in duration-700">
          <div className="mb-10 relative inline-block">
             <div className="w-20 h-20 border-4 border-cyan-400 bg-cyan-400/10 rotate-45 mx-auto mb-6 flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.4)]">
                <BrainCircuit className="w-10 h-10 text-cyan-400 -rotate-45" />
             </div>
             <h1 className="text-7xl font-orbitron font-black mb-2 tracking-tighter neon-text-cyan italic">
               MATH<span className="text-pink-500">DASH</span>
             </h1>
             <div className="flex items-center justify-center gap-4 bg-slate-900/60 p-2 rounded-full border border-slate-700">
               <span className="text-xs font-orbitron text-slate-400 px-2">AGE CALIBRATION:</span>
               {[6,7,8,9,10].map(a => (
                 <button 
                  key={a} 
                  onClick={() => setAge(a as AgeBracket)}
                  className={`w-8 h-8 rounded-full font-orbitron text-xs transition-all ${age === a ? 'bg-cyan-400 text-slate-900 shadow-[0_0_10px_rgba(34,211,238,0.8)]' : 'bg-slate-800 text-slate-500 hover:text-white'}`}
                 >
                   {a}
                 </button>
               ))}
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
            {[
              { m: GameMode.CLASSIC, i: <Zap/>, t: 'RUN', v: 'cyan', d: 'Progression & Precision' },
              { m: GameMode.BLITZ, i: <Timer/>, t: 'SPRINT', v: 'pink', d: '60s Chaos Rush' },
              { m: GameMode.ZEN, i: <InfinityIcon/>, t: 'FLOW', v: 'purple', d: 'Pure Practice' },
              { m: GameMode.DUEL, i: <Users/>, t: 'DUEL', v: 'cyan', d: 'Vs Cyber Logic Bot' }
            ].map(mode => (
              <div key={mode.m} className="bg-slate-900/50 border-2 border-slate-700 hover:border-cyan-400 p-4 rounded-xl flex flex-col items-center transition-all group">
                <div className="text-slate-400 group-hover:text-cyan-400 mb-2 transition-colors">{mode.i}</div>
                <h3 className="font-orbitron font-bold text-sm mb-1">{mode.m}</h3>
                <p className="text-[10px] text-slate-500 mb-4 uppercase">{mode.d}</p>
                <NeonButton variant={mode.v as any} onClick={() => startGame(mode.m)} className="w-full text-xs py-2">{mode.t}</NeonButton>
              </div>
            ))}
          </div>

          <button onClick={() => setGameState(GameState.LEADERBOARD)} className="text-slate-500 font-orbitron uppercase text-[10px] hover:text-white transition-all flex items-center gap-2 mx-auto">
            <Trophy size={12} /> ARCHIVED LOGIC
          </button>
        </div>
      )}

      {/* HUD & Duel Bar */}
      {gameState === GameState.PLAYING && (
        <div className="fixed top-0 left-0 w-full p-6 z-10 flex flex-col items-center">
          <div className="flex justify-between w-full mb-4">
            <div className="bg-slate-900/80 border border-cyan-400 p-2 rounded-lg backdrop-blur-md font-orbitron text-lg font-bold">
              <Zap size={16} className="inline mr-1 text-cyan-400" /> {stats.score}
            </div>
            {gameMode === GameMode.DUEL ? (
               <div className="w-1/2 bg-slate-800 h-6 rounded-full border border-slate-700 overflow-hidden relative shadow-[0_0_20px_rgba(0,0,0,0.5)]">
                  <div className="absolute inset-0 flex justify-between px-2 items-center text-[10px] font-orbitron font-bold z-10 uppercase">
                    <span>You</span>
                    <span>CyberBot</span>
                  </div>
                  <div className="h-full bg-cyan-400 absolute left-0 transition-all duration-300" style={{ width: `${stats.duelProgress/2}%` }} />
                  <div className="h-full bg-red-500 absolute right-0 transition-all duration-1000" style={{ width: `${stats.botProgress/2}%` }} />
               </div>
            ) : (
              <div className="font-orbitron font-black text-xl neon-text-cyan">{levels[stats.level-1]?.title}</div>
            )}
            <div className={`bg-slate-900/80 border p-2 rounded-lg backdrop-blur-md font-orbitron text-lg ${timeLeft < 5 ? 'border-red-500 animate-pulse text-red-500' : 'border-cyan-400'}`}>
              <Clock size={16} className="inline mr-1" /> {gameMode === GameMode.BLITZ ? globalTimeLeft : timeLeft}s
            </div>
          </div>
        </div>
      )}

      {/* Game Card */}
      {gameState === GameState.PLAYING && currentProblem && (
        <div className="relative">
          {feedback && <div className="absolute -top-24 left-1/2 -translate-x-1/2 w-full text-center animate-bounce neon-text-pink text-4xl font-orbitron font-black italic">{feedback}</div>}
          <GameCard problem={currentProblem} onAnswer={handleAnswer} isLocked={isAnswering} />
        </div>
      )}

      {/* Game Over */}
      {gameState === GameState.GAMEOVER && (
        <div className="text-center max-w-xl animate-in zoom-in duration-500 bg-slate-900/90 border-4 border-red-500 p-10 rounded-3xl">
          <h2 className="text-5xl font-orbitron font-black text-red-500 mb-2 italic">DASH_TERMINATED</h2>
          <div className="flex justify-center gap-8 my-8">
            <div><div className="text-[10px] text-slate-500 uppercase">Solved</div><div className="text-3xl font-orbitron font-bold">{stats.totalSolved}</div></div>
            <div><div className="text-[10px] text-slate-500 uppercase">Age</div><div className="text-3xl font-orbitron font-bold">{age}</div></div>
          </div>
          {mathFact && <div className="bg-cyan-500/10 border-l-4 border-cyan-400 p-4 mb-8 text-left text-xs italic"><Info className="inline mr-2" size={14}/> {mathFact}</div>}
          <div className="flex flex-col gap-3">
            <NeonButton onClick={() => startGame(gameMode)}>RE-INITIALIZE</NeonButton>
            <NeonButton variant="purple" onClick={() => setGameState(GameState.START)}>CMD_CENTER</NeonButton>
          </div>
        </div>
      )}

      {/* Leaderboard */}
      {gameState === GameState.LEADERBOARD && (
        <div className="w-full max-w-xl bg-slate-900/90 border-2 border-purple-500 p-8 rounded-2xl animate-in slide-in-from-right duration-500">
          <h2 className="text-3xl font-orbitron font-black text-purple-500 mb-6 flex items-center gap-3 italic"><Trophy/> LOGIC HALL</h2>
          <div className="space-y-2 mb-8 max-h-80 overflow-y-auto">
            {leaderboard.map((e, i) => (
              <div key={i} className="flex justify-between p-3 bg-slate-800/50 rounded-lg border border-slate-700">
                <span className="font-orbitron text-xs flex items-center gap-3"><span className="text-slate-500">#{i+1}</span> {e.name} <span className="text-[8px] bg-slate-700 px-1 rounded">{e.mode}</span></span>
                <span className="font-orbitron font-bold text-purple-400">{e.score}</span>
              </div>
            ))}
          </div>
          <NeonButton variant="purple" onClick={() => setGameState(GameState.START)} className="w-full">RETURN</NeonButton>
        </div>
      )}
    </div>
  );
};

export default App;
